import os
from pathlib import Path

ROOT = Path('/home/skynet/cabala-dos-caminhos')

# Scan for TypeScript/TSX files >= 500 lines
CODE_EXTS = {'.ts', '.tsx'}
SKIP_DIRS = {'node_modules', '.next', '.git', 'dist', 'build', '.turbo', '.cache'}

def count_lines(path):
    try:
        return sum(1 for line in path.read_text(encoding='utf-8', errors='ignore').splitlines() if line.strip())
    except OSError:
        return 0

oversized = []
for root, dirs, files in os.walk(ROOT):
    # Prune skip dirs in-place
    dirs[:] = [d for d in dirs if d not in SKIP_DIRS]

    for f in files:
        if Path(f).suffix.lower() in CODE_EXTS:
            fp = Path(root) / f
            lines = count_lines(fp)
            if lines >= 500:
                rel = fp.relative_to(ROOT)
                oversized.append((lines, str(rel)))

oversized.sort(reverse=True)
print(f'Total oversized files (>= 500 lines): {len(oversized)}')
print()
for lines, path in oversized[:60]:
    print(f'{lines:5d}L  {path}')

